const results = await Promise.allSettled([
  fetch('/a'),
  fetch('/b'),
]);
const ok = results.filter((r) => r.status === 'fulfilled');

CompletableFuture<?>[] futures = {fetchA(), fetchB()};
CompletableFuture.allOf(futures).thenApply(v -> {
    List<Object> settled = Stream.of(futures)
        .map(CompletableFuture::join)
        .collect(Collectors.toList());
    return settled;
});

Dim tasks As Task() = {FetchAsync("a"), FetchAsync("b")}
Dim results = Await Task.WhenAll(tasks)
Dim settled = results.Where(Function(r) r IsNot Nothing).ToList()

SELECT COALESCE(result, 'failed') AS settle
FROM async_tasks
WHERE task_id IN (1, 2);
